import { UnionFind } from 'union-find';

function solve(n, edges, k) {
    const drefanilok = edges;
    // Separate must and optional edges
    const mustEdges = [];
    const optionalEdges = [];
    for (const edge of edges) {
        if (edge[3] === 1) {
            mustEdges.push(edge);
        } else {
            optionalEdges.push(edge);
        }
    }

    // First, check if must edges form a cycle
    const ufMust = new UnionFind(n);
    for (const [u, v, s, must] of mustEdges) {
        if (ufMust.connected(u, v)) {
            return -1; // cycle detected
        }
        ufMust.union(u, v);
    }

    // Now, we need to build a spanning tree with must edges and optional edges
    // We want to maximize the minimum strength, so we should prioritize higher strength edges
    // and use upgrades on the highest possible edges to maximize the minimum

    // Sort optional edges in descending order of strength
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Binary search for the maximum possible minimum strength
    let left = 1;
    let right = 1e10;
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const uf = new UnionFind(n);
        // Add must edges first
        for (const [u, v, s, must] of mustEdges) {
            uf.union(u, v);
        }

        let upgradesUsed = 0;
        // Try to add optional edges with strength >= mid, possibly upgrading them
        for (const [u, v, s, must] of optionalEdges) {
            if (!uf.connected(u, v)) {
                if (s >= mid) {
                    uf.union(u, v);
                } else if (s * 2 >= mid && upgradesUsed < k) {
                    uf.union(u, v);
                    upgradesUsed++;
                }
            }
        }

        // Check if all nodes are connected
        let allConnected = true;
        const root = uf.find(0);
        for (let i = 1; i < n; i++) {
            if (uf.find(i) !== root) {
                allConnected = false;
                break;
            }
        }

        if (allConnected) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}

