)

type UnionFind struct {
	parent []int
	rank   []int
}

func NewUnionFind(size int64) *UnionFind {
	parent := make([]int, size)
	rank := make([]int, size)
	for i := range parent {
		parent[i] = i
		rank[i] = 0
	}
	return &UnionFind{parent, rank}
}

func (uf *UnionFind) Find(u int64) int64 {
	if uf.parent[u] != int(u) {
		uf.parent[u] = uf.Find(int64(uf.parent[u]))
	}
	return int64(uf.parent[u])
}

func (uf *UnionFind) Union(u, v int64) {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU == rootV {
		return
	}
	if uf.rank[rootU] > uf.rank[rootV] {
		uf.parent[rootV] = int(rootU)
	} else if uf.rank[rootU] < uf.rank[rootV] {
		uf.parent[rootU] = int(rootV)
	} else {
		uf.parent[rootV] = int(rootU)
		uf.rank[rootU]++
	}
}

func (uf *UnionFind) Connected(u, v int64) bool {
	return uf.Find(u) == uf.Find(v)
}

